+  <main class="game-shell" aria-label="Snake game">
+    <section class="topbar">
+      <div class="title">Snake</div>
+      <div class="metrics" aria-live="polite">
+        <span class="metric">Score<strong id="score">0</strong></span>
+        <span class="metric">Best<strong id="best">0</strong></span>
+      </div>
+    </section>
+
+    <section class="board-wrap">
+      <canvas id="board" width="560" height="560" aria-label="Snake board"></canvas>
+      <div class="overlay" id="overlay">
+        <div class="overlay-card">
+          <h2 id="overlay-title">Game Over</h2>
+          <p id="overlay-text" class="danger">You crashed. Try again!</p>
+          <button id="restart" type="button">Restart (Enter)</button>
+        </div>
+      </div>
+    </section>
+
+    <section class="footer">Use arrow keys to steer. Press Enter, Space, or R to restart after game over.</section>
+  </main>
+
+  <script>
+    (() => {
+      const GRID_SIZE = 20;
+      const BOARD_PIXELS = 560;
+      const CELL = BOARD_PIXELS / GRID_SIZE;
+      const START_SPEED = 9;
+      const SPEED_STEP = 0.2;
+      const STORAGE_KEY = "snake-best-score";
+
+      const canvas = document.getElementById("board");
+      const ctx = canvas.getContext("2d");
+      const scoreEl = document.getElementById("score");
+      const bestEl = document.getElementById("best");
+      const overlay = document.getElementById("overlay");
+      const overlayTitle = document.getElementById("overlay-title");
+      const overlayText = document.getElementById("overlay-text");
+      const restartBtn = document.getElementById("restart");
+
+      let snake;
+      let direction;
+      let queuedDirection;
+      let food;
+      let score;
+      let bestScore = Number(localStorage.getItem(STORAGE_KEY)) || 0;
+      let gameOver;
+      let lastTime = 0;
+      let accumulator = 0;
+      let speed = START_SPEED;
+
+      bestEl.textContent = String(bestScore);
+
+      function resetGame() {
+        snake = [
+          { x: 9, y: 10 },
+          { x: 8, y: 10 },
+          { x: 7, y: 10 }
+        ];
+        direction = { x: 1, y: 0 };
+        queuedDirection = direction;
+        food = spawnFood();
+        score = 0;
+        speed = START_SPEED;
+        gameOver = false;
+        accumulator = 0;
+        scoreEl.textContent = "0";
+        hideOverlay();
+      }
+
+      function spawnFood() {
+        while (true) {
+          const candidate = {
+            x: Math.floor(Math.random() * GRID_SIZE),
+            y: Math.floor(Math.random() * GRID_SIZE)
+          };
+          if (!snake.some((seg) => seg.x === candidate.x && seg.y === candidate.y)) {
+            return candidate;
+          }
+        }
+      }
+
+      function drawBoard() {
+        ctx.clearRect(0, 0, BOARD_PIXELS, BOARD_PIXELS);
+
+        for (let y = 0; y < GRID_SIZE; y++) {
+          for (let x = 0; x < GRID_SIZE; x++) {
+            const checker = (x + y) % 2 === 0;
+            ctx.fillStyle = checker ? "#0d1528" : "#0b1324";
+            ctx.fillRect(x * CELL, y * CELL, CELL, CELL);
+          }
+        }
+
+        ctx.strokeStyle = "rgba(148, 163, 184, 0.08)";
+        ctx.lineWidth = 1;
+        for (let i = 0; i <= GRID_SIZE; i++) {
+          const p = i * CELL + 0.5;
+          ctx.beginPath();
+          ctx.moveTo(p, 0);
+          ctx.lineTo(p, BOARD_PIXELS);
+          ctx.stroke();
+          ctx.beginPath();
+          ctx.moveTo(0, p);
+          ctx.lineTo(BOARD_PIXELS, p);
+          ctx.stroke();
+        }
+      }
+
+      function drawFood() {
+        const px = food.x * CELL;
+        const py = food.y * CELL;
+        const center = CELL / 2;
+
+        ctx.fillStyle = "rgba(249,115,22,0.2)";
+        ctx.beginPath();
+        ctx.arc(px + center, py + center, CELL * 0.42, 0, Math.PI * 2);
+        ctx.fill();
+
+        ctx.fillStyle = "#fb923c";
+        ctx.beginPath();
+        ctx.arc(px + center, py + center, CELL * 0.28, 0, Math.PI * 2);
+        ctx.fill();
+
+        ctx.fillStyle = "#fff7ed";
+        ctx.beginPath();
+        ctx.arc(px + center - 3, py + center - 3, CELL * 0.08, 0, Math.PI * 2);
+        ctx.fill();
+      }
+
+      function drawSnake() {
+        snake.forEach((segment, index) => {
+          const px = segment.x * CELL;
+          const py = segment.y * CELL;
+          const isHead = index === 0;
+          const radius = isHead ? 7 : 6;
+
+          const grad = ctx.createLinearGradient(px, py, px + CELL, py + CELL);
+          if (isHead) {
+            grad.addColorStop(0, "#4ade80");
+            grad.addColorStop(1, "#16a34a");
+          } else {
+            grad.addColorStop(0, "#22c55e");
+            grad.addColorStop(1, "#15803d");
+          }
+
+          roundRect(px + 1.5, py + 1.5, CELL - 3, CELL - 3, radius, grad);
+
+          if (isHead) {
+            const eyeY = py + CELL * 0.35;
+            ctx.fillStyle = "#ecfeff";
+            ctx.beginPath();
+            ctx.arc(px + CELL * 0.35, eyeY, 2.1, 0, Math.PI * 2);
+            ctx.arc(px + CELL * 0.65, eyeY, 2.1, 0, Math.PI * 2);
+            ctx.fill();
+          }
+        });
+      }
+
+      function roundRect(x, y, w, h, r, fillStyle) {
+        ctx.fillStyle = fillStyle;
+        ctx.beginPath();
+        ctx.moveTo(x + r, y);
+        ctx.lineTo(x + w - r, y);
+        ctx.quadraticCurveTo(x + w, y, x + w, y + r);
+        ctx.lineTo(x + w, y + h - r);
+        ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
+        ctx.lineTo(x + r, y + h);
+        ctx.quadraticCurveTo(x, y + h, x, y + h - r);
+        ctx.lineTo(x, y + r);
+        ctx.quadraticCurveTo(x, y, x + r, y);
+        ctx.closePath();
+        ctx.fill();
+      }
+
+      function step() {
+        direction = queuedDirection;
+        const head = snake[0];
+        const next = { x: head.x + direction.x, y: head.y + direction.y };
+
+        const hitsWall =
+          next.x < 0 ||
+          next.y < 0 ||
+          next.x >= GRID_SIZE ||
+          next.y >= GRID_SIZE;
+
+        const hitsSelf = snake.some((segment) => segment.x === next.x && segment.y === next.y);
+
+        if (hitsWall || hitsSelf) {
+          endGame();
+          return;
+        }
+
+        snake.unshift(next);
+
+        if (next.x === food.x && next.y === food.y) {
+          score += 10;
+          speed += SPEED_STEP;
+          scoreEl.textContent = String(score);
+          food = spawnFood();
+
+          if (score > bestScore) {
+            bestScore = score;
+            localStorage.setItem(STORAGE_KEY, String(bestScore));
+            bestEl.textContent = String(bestScore);
+          }
+        } else {
+          snake.pop();
+        }
+      }
+
+      function endGame() {
+        gameOver = true;
+        overlayTitle.textContent = "Game Over";
+        overlayText.textContent = `Final score: ${score}`;
+        overlayText.classList.remove("danger");
+        showOverlay();
+      }
+
+      function showOverlay() {
+        overlay.classList.add("show");
+      }
+
+      function hideOverlay() {
+        overlay.classList.remove("show");
+      }
+
+      function onKeyDown(event) {
+        const key = event.key;
+        const isArrow = key.startsWith("Arrow");
+        if (isArrow || key === " " || key === "Enter") {
+          event.preventDefault();
+        }
+
+        if (gameOver && (key === "Enter" || key === " " || key.toLowerCase() === "r")) {
+          resetGame();
+          return;
+        }
+
+        if (gameOver) {
+          return;
+        }
+
+        const map = {
+          ArrowUp: { x: 0, y: -1 },
+          ArrowDown: { x: 0, y: 1 },
+          ArrowLeft: { x: -1, y: 0 },
+          ArrowRight: { x: 1, y: 0 }
+        };
+
+        const nextDir = map[key];
+        if (!nextDir) {
+          return;
+        }
+
+        if (nextDir.x === -direction.x && nextDir.y === -direction.y) {
+          return;
+        }
+
+        queuedDirection = nextDir;
+      }
+
+      function tick(timestamp) {
+        if (!lastTime) {
+          lastTime = timestamp;
+        }
+        const delta = timestamp - lastTime;
+        lastTime = timestamp;
+
+        if (!gameOver) {
+          accumulator += delta;
+          const frameTime = 1000 / speed;
+          while (accumulator >= frameTime) {
+            step();
+            accumulator -= frameTime;
+            if (gameOver) {
+              break;
+            }
+          }
+        }
+
+        drawBoard();
+        drawFood();
+        drawSnake();
+        requestAnimationFrame(tick);
+      }
+
+      restartBtn.addEventListener("click", () => {
+        resetGame();
+      });
+      window.addEventListener("keydown", onKeyDown, { passive: false });
+
+      resetGame();
+      requestAnimationFrame(tick);
+    })();
+  </script>
+</body>
+</html>
*** End Patch

